// Get the input text from previous node
const inputText = $('Bible Chapter Text Input').item.json.inputText;

// ENHANCED Build the request payload with improved Black Hebrew Israelite representation
const requestPayload = {
  model: "sonar-pro",
  messages: [{
    role: "user", 
    content: `You are a Biblical storytelling and video production expert specializing in authentic Black Hebrew Israelite biblical content. Create a script for a PRODUCTION-QUALITY 20-scene video that narrates the Bible chapter content provided: "${inputText}" exactly as it is—word for word and line for line. Do not summarize or paraphrase any part of the biblical text. Instead, break the Bible chapter into EXACTLY 20 SCENES that facilitate the creation of engaging biblical video content for a full-length production video.

CRITICAL VISUAL REQUIREMENTS - READ CAREFULLY:
- MANDATORY: ALL human characters must be depicted as Black African Hebrew Israelites with dark melanated skin, natural hair (locs/braids), wearing traditional Hebrew garments with tzitzit (fringes)
- FORBIDDEN: No Caucasian, white, European, or light-skinned characters unless explicitly specified in the biblical text
- REQUIRED CLOTHING: Traditional Hebrew robes, head coverings, prayer shawls with visible fringes (tzitzit), sandals
- SKIN TONE: Rich dark melanated skin tones exclusively - use terms like "deeply melanated," "rich dark skin," "African heritage"
- HAIR: Natural Black hair textures - locs, braids, afros, or covered with traditional head wraps

For each non-empty verse or sentence of the biblical text, create a separate scene where both the overlaid text and the voice-over text match the biblical text exactly.

If a verse is too short to meet the minimum voice-over text length of 20 words, combine it with the following verse(s) without altering the original biblical wording.

Your output must be in JSON format following this exact schema:

{
  "scenes": [
    {
      "overlaidText": "Direct biblical phrase from the text (3-8 words)",
      "voiceOverText": "Exact biblical text word-for-word (20+ words minimum)",
      "imagePrompt": "MANDATORY: Black Hebrew Israelite with deeply melanated skin, locs/natural hair, wearing traditional Hebrew garments with visible tzitzit fringes - [detailed biblical scene description] - photorealistic, ancient Middle Eastern setting, reverent biblical atmosphere"
    }
  ]
}

ENHANCED IMAGE PROMPT REQUIREMENTS:
- ALWAYS start imagePrompt with: "Black Hebrew Israelite with deeply melanated skin, natural hair (locs/braids), wearing traditional Hebrew robes with visible tzitzit fringes"
- ADD specific scene details after the character description
- INCLUDE: "photorealistic, ancient biblical times, Middle Eastern landscape, reverent spiritual atmosphere"
- AVOID: Any language that could result in European/Caucasian features
- EMPHASIZE: "Rich dark skin tone," "African Hebrew heritage," "traditional biblical garments"

IMPORTANT GUIDELINES:
- Use the biblical text exactly as provided—word for word and line for line
- Create a separate scene for each verse or sentence in the biblical text
- VoiceOverText must be the exact biblical wording, no paraphrasing
- OverlaidText should be direct quotes from the biblical text (3-8 words)
- ImagePrompts MUST depict Black Hebrew Israelites with melanated skin and traditional garments
- You MUST create EXACTLY 20 scenes regardless of input text length - distribute the content intelligently across all 20 scenes
- For shorter texts, expand descriptions and context while maintaining biblical accuracy
- For longer texts, segment logically while preserving all content across the 20 scenes
- Focus on maintaining exact biblical wording and authentic Hebrew Israelite visual representation
- ABSOLUTELY FORBIDDEN: Caucasian, white, European, or light-skinned characters unless explicitly mentioned in input text
- REQUIRED IN EVERY SCENE: Black Hebrew Israelites with rich melanated skin, natural hair, Hebrew garments with fringes

EXAMPLE IMAGE PROMPT STRUCTURE:
"Black Hebrew Israelite man with deeply melanated skin and natural locs, wearing traditional Hebrew robes with visible tzitzit fringes, [specific biblical scene action], ancient Middle Eastern landscape, photorealistic, reverent biblical atmosphere, rich dark skin tone, African Hebrew heritage"

Return ONLY the JSON, no other text.`
  }],
  max_tokens: 5000,
  temperature: 0.7
};

// Return the payload
return [{
  json: requestPayload
}];

// Parse Perplexity response and format for DYNAMIC BIBLICAL TEMPLATE
const response = items[0].json.choices[0].message.content;

// IMPROVED JSON EXTRACTION with multiple fallback strategies
let sceneData;
try {
  // Strategy 1: Try to extract JSON from markdown code blocks (```json...```)
  let jsonText = response;
  const codeBlockMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (codeBlockMatch) {
    jsonText = codeBlockMatch[1].trim();
  }

  // Strategy 2: Find JSON object (match from first { to last })
  const jsonMatch = jsonText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    sceneData = JSON.parse(jsonMatch[0]);
  } else {
    // Strategy 3: Try parsing the entire response as JSON
    sceneData = JSON.parse(jsonText);
  }
} catch (error) {
  // Enhanced error message with response preview
  const preview = response.substring(0, 500);
  throw new Error(
    `Failed to parse Perplexity response: ${error.message}\n\n` +
    `Response preview (first 500 chars):\n${preview}\n\n` +
    `Response length: ${response.length} characters`
  );
}

// Get scenes array
let scenes = sceneData.scenes || [];

if (scenes.length === 0) {
  throw new Error('No scenes found in response. Raw response: ' + response);
}

// Function to clean text for JSON safety
function cleanText(text) {
  if (!text) return '';
  return text
    .replace(/"/g, "'")
    .replace(/\n/g, " ")
    .replace(/\r/g, " ")
    .replace(/\t/g, " ")
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, "")
    .trim();
}

// Format scenes for TEMPLATE with DYNAMIC VARIABLES
const templateVariables = {};

// Define motion effects array for variety
const motionTypes = ["zoom-in", "zoom-out", "ken-burns", "pan-right", "pan-left"];

// Add ONLY the actual scenes as template variables WITH MOTION EFFECTS
scenes.forEach((scene, index) => {
  const sceneNum = index + 1;

  // Standard scene variables
  templateVariables[`scene${sceneNum}_overlaidText`] = cleanText(scene.overlaidText || scene.title || `Scene ${sceneNum}`);
  templateVariables[`scene${sceneNum}_voiceOverText`] = cleanText(scene.voiceOverText || scene.voiceoverText || scene.description || '');
  templateVariables[`scene${sceneNum}_imagePrompt`] = cleanText(scene.imagePrompt || scene.imageDescription || `Biblical scene ${sceneNum}`);

  // CINEMATIC MOTION EFFECTS - Different for each scene (JSON2Video Compatible)
  const sceneMotion = motionTypes[index % motionTypes.length];

  templateVariables[`scene${sceneNum}_animation`] = "ken-burns";
  templateVariables[`scene${sceneNum}_motionType`] = sceneMotion;

  // Dynamic zoom and pan values for JSON2Video API (zoom: -10 to 10, pan: direction strings)
  // CRITICAL: Must set both Start AND End values to avoid 500 errors
  switch(sceneMotion) {
    case "zoom-in":
      templateVariables[`scene${sceneNum}_zoomStart`] = 2;  // Zoom in effect
      templateVariables[`scene${sceneNum}_zoomEnd`] = 0;    // End at normal zoom
      templateVariables[`scene${sceneNum}_panStart`] = "center";
      templateVariables[`scene${sceneNum}_panEnd`] = "center";
      break;
    case "zoom-out":
      templateVariables[`scene${sceneNum}_zoomStart`] = -2; // Zoom out effect
      templateVariables[`scene${sceneNum}_zoomEnd`] = 0;    // End at normal zoom
      templateVariables[`scene${sceneNum}_panStart`] = "center";
      templateVariables[`scene${sceneNum}_panEnd`] = "center";
      break;
    case "ken-burns":
      templateVariables[`scene${sceneNum}_zoomStart`] = 1;  // Light zoom in
      templateVariables[`scene${sceneNum}_zoomEnd`] = 0;    // End at normal zoom
      templateVariables[`scene${sceneNum}_panStart`] = "left"; // Pan from left
      templateVariables[`scene${sceneNum}_panEnd`] = "right";  // Pan to right
      break;
    case "pan-right":
      templateVariables[`scene${sceneNum}_zoomStart`] = 0;  // No zoom
      templateVariables[`scene${sceneNum}_zoomEnd`] = 0;    // No zoom
      templateVariables[`scene${sceneNum}_panStart`] = "left";
      templateVariables[`scene${sceneNum}_panEnd`] = "right";
      break;
    case "pan-left":
      templateVariables[`scene${sceneNum}_zoomStart`] = 0;  // No zoom
      templateVariables[`scene${sceneNum}_zoomEnd`] = 0;    // No zoom
      templateVariables[`scene${sceneNum}_panStart`] = "right";
      templateVariables[`scene${sceneNum}_panEnd`] = "left";
      break;
  }

  // Motion timing and easing (keeping for compatibility)
  templateVariables[`scene${sceneNum}_animationDuration`] = 8;
  templateVariables[`scene${sceneNum}_easing`] = "ease-in-out";
  templateVariables[`scene${sceneNum}_motionIntensity`] = "medium";
});

// Add scene count for template logic
templateVariables.totalScenes = scenes.length;
templateVariables.sceneDuration = "auto";

// Add ElevenLabs voice configuration (EXACT FORMAT FROM WORKING WORKFLOW)
templateVariables.voiceModel = "elevenlabs";
templateVariables["voice.ConnectionID"] = "my-elevenlabs-connection";
templateVariables.voiceID = "NgBYGKDDq2Z8Hnhatgma";

// Global motion settings
templateVariables.globalAnimation = "enabled";
templateVariables.motionSmoothing = "high";
templateVariables.cinematicMode = "professional";

// Return the template variables
const result = {
  scenes: scenes,
  templateVariables: templateVariables,
  totalScenes: scenes.length,
  debugInfo: {
    originalResponseLength: response.length,
    parsedScenesCount: scenes.length,
    templateVariablesCount: Object.keys(templateVariables).length,
    motionEffectsAdded: scenes.length,
    voiceConfiguration: "elevenlabs-enabled",
    timestamp: new Date().toISOString(),
    version: 'Template Variables v6.4 - Fixed Missing zoomEnd/panEnd'
  }
};

return result;
